),
unique_task_matches as (
  select
    task_id,
    min(estimate_work_id) as estimate_work_id
  from candidate_pairs
  group by task_id
  having count(*) = 1
),
unique_estimate_matches as (
  select
    estimate_work_id,
    min(task_id) as task_id
  from candidate_pairs
  group by estimate_work_id
  having count(*) = 1
),
resolved_matches as (
  select
    utm.task_id,
    utm.estimate_work_id
  from unique_task_matches utm
  join unique_estimate_matches uem
    on uem.task_id = utm.task_id
   and uem.estimate_work_id = utm.estimate_work_id
)
update public.tasks t
